// query variablen er automatisk tilgængelig fra agenten
const embeddingResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:11434/api/embeddings',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    model: 'nomic-embed-text',
    prompt: query
  })
});

const embedding = embeddingResponse.embedding;

const neo4jResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:7474/db/neo4j/tx/commit',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Basic ' + Buffer.from('neo4j:hajiyard2026').toString('base64')
  },
  body: JSON.stringify({
    statements: [{
      statement: `
        MATCH (p:Plant)-[:HAS_CHUNK]->(c:Chunk)
        WITH p, c,
          reduce(dot = 0.0, i IN range(0, size(c.embedding)-1) |
            dot + c.embedding[i] * $embedding[i]) /
          (sqrt(reduce(a = 0.0, i IN range(0, size(c.embedding)-1) |
            a + c.embedding[i]^2)) *
           sqrt(reduce(b = 0.0, i IN range(0, size($embedding)-1) |
            b + $embedding[i]^2))) AS similarity
        WHERE similarity > 0.7
        RETURN p.name_en, p.name_da, c.text, similarity
        ORDER BY similarity DESC
        LIMIT 5
      `,
      parameters: { embedding }
    }]
  })
});

const results = neo4jResponse.results[0]?.data || [];
if (results.length === 0) return 'No relevant plants found.';

return results.map(r => 
  `Plant: ${r.row[0]} (${r.row[1]})\n${r.row[2]}`
).join('\n\n---\n\n');

const neo4jResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:7474/db/neo4j/tx/commit',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Basic ' + Buffer.from('neo4j:hajiyard2026').toString('base64')
  },
  body: JSON.stringify({
    statements: [{
      statement: `
        MATCH (p:Plant)
        WHERE toLower(p.name_en) CONTAINS toLower($plant_name)
        OPTIONAL MATCH (p)-[:GROWS_WELL_WITH]->(good:Plant)
        OPTIONAL MATCH (p)-[:ANTAGONIZES]->(bad:Plant)
        OPTIONAL MATCH (p)-[:FOLLOWS_WELL_AFTER]->(after:Plant)
        OPTIONAL MATCH (p)-[:AVOID_AFTER]->(avoid:Plant)
        OPTIONAL MATCH (p)-[:PREFERS_SOIL]->(soil:SoilType)
        OPTIONAL MATCH (p)-[:DEPLETES]->(dep:Nutrient)
        OPTIONAL MATCH (p)-[:RESTORES]->(res:Nutrient)
        OPTIONAL MATCH (p)-[:GROWS_IN]->(season:Season)
        OPTIONAL MATCH (p)-[:BELONGS_TO]->(family:Family)
        RETURN p.name_en, p.name_da, p.name_latin,
          collect(DISTINCT good.name_en) as grows_well_with,
          collect(DISTINCT bad.name_en) as antagonizes,
          collect(DISTINCT after.name_en) as follows_well_after,
          collect(DISTINCT avoid.name_en) as avoid_after,
          collect(DISTINCT soil.name) as prefers_soil,
          collect(DISTINCT dep.name) as depletes,
          collect(DISTINCT res.name) as restores,
          collect(DISTINCT season.name) as grows_in,
          collect(DISTINCT family.name) as family
        LIMIT 1
      `,
      parameters: { plant_name: query }
    }]
  })
});

const results = neo4jResponse.results[0]?.data || [];
if (results.length === 0) return `No plant found matching "${query}".`;

const r = results[0].row;
return `Plant: ${r[0]} (${r[1]}, ${r[2]})
Grows well with: ${r[3].join(', ') || 'none'}
Antagonizes: ${r[4].join(', ') || 'none'}
Follows well after: ${r[5].join(', ') || 'none'}
Avoid after: ${r[6].join(', ') || 'none'}
Prefers soil: ${r[7].join(', ') || 'unknown'}
Depletes: ${r[8].join(', ') || 'none'}
Restores: ${r[9].join(', ') || 'none'}
Grows in: ${r[10].join(', ') || 'unknown'}
Family: ${r[11].join(', ') || 'unknown'}`;

let queryString = query;
if (typeof query === 'object' && query !== null) {
  queryString = Object.values(query).filter(v => typeof v === 'string').join(' ');
}

const daToEn = {
  'forår': 'spring', 'foråret': 'spring',
  'sommer': 'summer', 'sommeren': 'summer',
  'efterår': 'fall', 'efteråret': 'fall',
  'vinter': 'winter', 'vinteren': 'winter',
  'sandjord': 'sandy', 'sandede': 'sandy', 'sand': 'sandy',
  'lerjord': 'clay', 'lerede': 'clay', 'ler': 'clay',
  'siltet': 'silty', 'siltjord': 'silty',
  'kalkholdig': 'chalky', 'kalk': 'chalky',
  'tørvejord': 'peaty', 'tørv': 'peaty',
  'muld': 'loamy',
  'veldrænet': 'well-drained', 'drænet': 'well-drained',
  'fugtig': 'moist', 'fugtigt': 'moist',
  'våd': 'wet', 'vådt': 'wet'
};

const translatedTerms = queryString.toLowerCase().split(/[\s,]+/).map(t => daToEn[t] || t);
const terms = translatedTerms;

const seasons = ['spring', 'summer', 'fall', 'winter'];
const soilTypes = ['sandy', 'loamy', 'clay', 'chalky', 'peaty', 'silty'];
const moistureTypes = ['well-drained', 'moist but well-drained', 'moist', 'wet', 'poorly drained'];

const matchedSeasons = terms.filter(t => seasons.includes(t));
const matchedSoils = terms.filter(t => soilTypes.includes(t));
const matchedMoisture = moistureTypes.filter(m =>
  terms.some(t => m.includes(t) || t.includes(m))
);

// Build dynamic Cypher based on what was matched
let matchClauses = ['MATCH (p:Plant)'];
let whereClauses = [];
let parameters = {};

if (matchedSeasons.length > 0) {
  matchClauses.push('MATCH (p)-[:GROWS_IN]->(s:Season)');
  whereClauses.push('s.name IN $seasons');
  parameters.seasons = matchedSeasons;
}

if (matchedSoils.length > 0) {
  matchClauses.push('MATCH (p)-[:PREFERS_SOIL]->(soil:SoilType)');
  whereClauses.push('soil.name IN $soils');
  parameters.soils = matchedSoils;
}

if (matchedMoisture.length > 0) {
  matchClauses.push('MATCH (p)-[:PREFERS_MOISTURE]->(moist:Moisture)');
  whereClauses.push('moist.name IN $moisture');
  parameters.moisture = matchedMoisture;
}

if (Object.keys(parameters).length === 0) {
  return `Could not identify any season, soil type or moisture in "${query}". Use terms like: spring, summer, fall, winter, sandy, loamy, clay, chalky, well-drained, moist.`;
}

const whereStr = whereClauses.length > 0 ? 'WHERE ' + whereClauses.join(' AND ') : '';
const statement = `
  ${matchClauses.join('\n  ')}
  ${whereStr}
  RETURN DISTINCT p.name_en, p.name_da
  ORDER BY p.name_en LIMIT 20
`;

const neo4jResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:7474/db/neo4j/tx/commit',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Basic ' + Buffer.from('neo4j:hajiyard2026').toString('base64')
  },
  body: JSON.stringify({ statements: [{ statement, parameters }] })
});

const results = neo4jResponse.results[0]?.data || [];
if (results.length === 0) return `No plants found for "${query}".`;

return results.map(r => `${r.row[0]} (${r.row[1] || 'no Danish name'})`).join('\n');
